  6	import { useForkliftTranslation } from 'src/utils/i18n';
  7	
  8	import {
  9	  Button,
 10	  ButtonVariant,
 11	  Divider,
 12	  Form,
 13	  InputGroup,
 14	  TextInput,
 15	} from '@patternfly/react-core';
 16	import { EyeIcon, EyeSlashIcon } from '@patternfly/react-icons';
 17	import type { ValidationMsg } from '@utils/validation/Validation';
 18	
 19	import { esxiSecretFieldValidator } from './utils/esxiSecretFieldValidator';
 20	import { getDecodedValue } from './utils/getDecodedValue';
 21	import CertificateEditSection from './CertificateEditSection';
 22	
 23	const EsxiCredentialsEdit: FC<CredentialsEditModeByTypeProps> = ({ onNewSecretChange, secret }) => {
 24	  const { t } = useForkliftTranslation();
 25	
 26	  const user = getDecodedValue(secret?.data?.user);
 27	  const password = getDecodedValue(secret?.data?.password);
 28	  const url = getDecodedValue(secret?.data?.url);
 29	  const cacert = getDecodedValue(secret?.data?.cacert);
 30	  const insecureSkipVerify = getDecodedValue(secret?.data?.insecureSkipVerify);
 31	
 32	  const [passwordHidden, setPasswordHidden] = useState<boolean>(true);
 33	  const [userValidation, setUserValidation] = useState<ValidationMsg>(
 34	    esxiSecretFieldValidator(SecretFieldsId.User, user!),
 35	  );
 36	  const [passwordValidation, setPasswordValidation] = useState<ValidationMsg>(
 37	    esxiSecretFieldValidator(SecretFieldsId.Password, password!),
 38	  );
 39	  const [cacertValidation, setCacertValidation] = useState<ValidationMsg>(
 40	    esxiSecretFieldValidator(SecretFieldsId.CaCert, cacert!),
 41	  );
 42	  const [insecureSkipVerifyValidation, setInsecureSkipVerifyValidation] = useState<ValidationMsg>(
 43	    esxiSecretFieldValidator(SecretFieldsId.InsecureSkipVerify, insecureSkipVerify!),
 44	  );
 45	
 46	  const handleChange = useCallback(
 47	    (id: SecretFieldsId, value: string) => {
 48	      const validationState = esxiSecretFieldValidator(id, value);
 49	
 50	      if (id === SecretFieldsId.User) setUserValidation(validationState);
 51	      if (id === SecretFieldsId.Password) setPasswordValidation(validationState);
 52	      if (id === SecretFieldsId.InsecureSkipVerify)
 53	        setInsecureSkipVerifyValidation(validationState);
 54	      if (id === SecretFieldsId.CaCert) setCacertValidation(validationState);
 55	
 56	      // don't trim fields that allow spaces
 57	      const encodedValue =
 58	        id === SecretFieldsId.CaCert ? encode(value ?? '') : encode(value?.trim() ?? '');
 59	
 60	      onNewSecretChange({ ...secret, data: { ...secret.data, [id]: encodedValue } });
 61	    },
 62	    [secret, onNewSecretChange],
 63	  );
 64	
 65	  const onClickTogglePassword = () => {
 66	    setPasswordHidden(!passwordHidden);
 67	  };
 68	
 69	  const onChangeUser: (_event: FormEvent<HTMLInputElement>, value: string) => void = (
 70	    _event,
 71	    value,
 72	  ) => {
 73	    handleChange(SecretFieldsId.User, value);
 74	  };
 75	
 76	  const onChangePassword: (_event: FormEvent<HTMLInputElement>, value: string) => void = (
 77	    _event,
 78	    value,
 79	  ) => {
 80	    handleChange(SecretFieldsId.Password, value);
 81	  };
 82	
 83	  const onChangeInsecure: (_event: FormEvent<HTMLInputElement>, checked: boolean) => void = (
 84	    _event,
 85	    checked,
 86	  ) => {
 87	    handleChange(SecretFieldsId.InsecureSkipVerify, checked ? 'true' : 'false');
 88	  };
 89	
 90	  const onDataChange: (data: string) => void = (data) => {
 91	    handleChange(SecretFieldsId.CaCert, data);
 92	  };
 93	
 94	  return (
 95	    <Form isWidthLimited className="forklift-section-secret-edit">
 96	      <FormGroupWithHelpText
 97	        label={t('Username')}
 98	        isRequired
 99	        fieldId="user"
100	        helperText={userValidation.msg}
101	        helperTextInvalid={userValidation.msg}
102	        validated={userValidation.type}
103	      >
104	        <TextInput
105	          data-testid="provider-username-input"
106	          spellCheck="false"
107	          isRequired
108	          type="text"
109	          id="user"
110	          name="user"
111	          onChange={onChangeUser}
112	          value={user}
113	          validated={userValidation.type}
114	        />
115	      </FormGroupWithHelpText>
116	      <FormGroupWithHelpText
117	        label={t('Password')}
118	        isRequired
119	        fieldId="password"
120	        helperText={passwordValidation.msg}
121	        helperTextInvalid={passwordValidation.msg}
122	        validated={passwordValidation.type}
123	      >
124	        <InputGroup>
125	          <TextInput
126	            data-testid="provider-password-input"
127	            spellCheck="false"
128	            isRequired
129	            type={passwordHidden ? 'password' : 'text'}
130	            aria-label="Password input"
131	            onChange={onChangePassword}
132	            value={password}
133	            validated={passwordValidation.type}
134	          />
135	          <Button
136	            variant={ButtonVariant.control}
137	            onClick={onClickTogglePassword}
138	            aria-label={passwordHidden ? 'Show password' : 'Hide password'}
139	          >
140	            {passwordHidden ? <EyeIcon /> : <EyeSlashIcon />}
141	          </Button>
142	        </InputGroup>
143	      </FormGroupWithHelpText>
144	
145	      <Divider />
146	
147	      <CertificateEditSection
148	        insecureSkipVerifyValidation={insecureSkipVerifyValidation}
149	        insecureSkipVerify={insecureSkipVerify}
150	        cacertValidation={cacertValidation}
151	        cacert={cacert}
152	        url={url}
153	        onChangeInsecure={onChangeInsecure}
154	        onDataChange={onDataChange}
155	      />
156	    </Form>
157	  );
158	};
159	
160	export default EsxiCredentialsEdit;

